   1 &amp; 2 &amp; 1  \cr 
   4 &amp; 3 &amp; 1  \cr 
   3 &amp; 5 &amp; 1  \cr 

 } } \right| + {1 \over 2}\left| {\matrix{
   4 &amp; 3 &amp; 1  \cr 
   6 &amp; 6 &amp; 1  \cr 
   3 &amp; 5 &amp; 1  \cr 

 } } \right|$$<br><br>$$ = {1 \over 2}\left[ {\left| {\matrix{
   1 &amp; 2 &amp; 1  \cr 
